/**
 * ACPX Mission Type Definitions
 * Core types for mission representation and round artifact generation.
 */

// ---------------------------------------------------------------------------
// Mission State
// ---------------------------------------------------------------------------

export enum MissionState {
  Pending = "pending",
  Active = "active",
  Paused = "paused",
  Completed = "completed",
  Failed = "failed",
}

// ---------------------------------------------------------------------------
// Mission Metadata
// ---------------------------------------------------------------------------

export interface MissionMetadata {
  id: string;
  name: string;
  description: string;
  createdAt: string; // ISO-8601
  updatedAt: string; // ISO-8601
  ownerId: string;
  tags?: string[];
}

// ---------------------------------------------------------------------------
// Round Artifact (lightweight structure for round-by-round generation)
// ---------------------------------------------------------------------------

export interface RoundArtifact {
  roundIndex: number;
  schema: string; // JSON Schema string for artifact payload
  payload: Record<string, unknown>;
  createdAt: string; // ISO-8601
}

export interface RoundArtifactSchema {
  type: string;
  properties: Record<string, unknown>;
  required?: string[];
}

// ---------------------------------------------------------------------------
// Mission Contract (top-level export)
// ---------------------------------------------------------------------------

export interface MissionContract {
  metadata: MissionMetadata;
  state: MissionState;
  currentRound: number;
  totalRounds: number;
  artifacts: RoundArtifact[];
}

export type { RoundArtifactSchema as ArtifactSchema };

